1	import { useState, useRef, useEffect } from 'react'
2	import './CardTile.css'
3	
4	export default function CardTile({ card, onCardClick, onUpdate }) {
5	  const [isEditingTitle, setIsEditingTitle]       = useState(false)
6	  const [editTitle, setEditTitle]                 = useState(card.title)
7	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
8	  const [editAssignee, setEditAssignee]           = useState(card.assignee ?? '')
9	  const [isSaving, setIsSaving]                   = useState(false)
10	  const [saveError, setSaveError]                 = useState(null)
11	  const skipBlurRef                               = useRef(false)
12	  const titleInputRef                             = useRef(null)
13	  const assigneeInputRef                          = useRef(null)
14	
15	  // Auto-focus input when entering edit mode (mirrors CardModal pattern)
16	  useEffect(() => {
17	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
18	  }, [isEditingTitle])
19	
20	  useEffect(() => {
21	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
22	  }, [isEditingAssignee])
23	
24	  async function handleSaveTitle() {
25	    if (editTitle.trim() === '') { setSaveError('Title is required'); return }
26	    setIsSaving(true); setSaveError(null)
27	    try {
28	      await onUpdate(card.id, { title: editTitle })
29	      setIsEditingTitle(false)
30	    } catch (err) {
31	      setEditTitle(card.title)        // local rollback
32	      setIsEditingTitle(false)        // exit edit mode on failure
33	      setSaveError(err.message)
34	    } finally { setIsSaving(false) }
35	  }
36	
37	  async function handleSaveAssignee() {
38	    setIsSaving(true); setSaveError(null)
39	    try {
40	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
41	      setIsEditingAssignee(false)
42	    } catch (err) {
43	      setEditAssignee(card.assignee ?? '')  // local rollback
44	      setIsEditingAssignee(false)
45	      setSaveError(err.message)
46	    } finally { setIsSaving(false) }
47	  }
48	
49	  const isEditing = isEditingTitle || isEditingAssignee
50	
51	  return (
52	    <div
53	      className={`card-tile${isEditing ? ' card-tile-editing' : ''}`}
54	      role="button"
55	      tabIndex={0}
56	      onClick={() => !isEditing && onCardClick(card)}
57	      onKeyDown={e => {
58	        if (isEditing) return
59	        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onCardClick(card) }
60	      }}
61	      aria-label={card.title}
62	    >
63	      {/* Title */}
64	      {isEditingTitle ? (
65	        <div className="card-tile-field-edit">
66	          <input
67	            ref={titleInputRef}
68	            aria-label="Edit title"
69	            value={editTitle}
70	            onChange={e => setEditTitle(e.target.value)}
71	            onKeyDown={e => {
72	              if (e.key === 'Enter')  { skipBlurRef.current = true; handleSaveTitle() }
73	              if (e.key === 'Escape') { skipBlurRef.current = true; setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }
74	            }}
75	            onBlur={() => {
76	              if (skipBlurRef.current) { skipBlurRef.current = false; return }
77	              handleSaveTitle()
78	            }}
79	          />
80	          {isSaving && <span aria-label="Saving">Saving…</span>}
81	        </div>
82	      ) : (
83	        <h3
84	          className="card-tile-title"
85	          onClick={e => {
86	            e.stopPropagation()
87	            setEditTitle(card.title)
88	            setIsEditingTitle(true)
89	            // Mutual exclusivity: close assignee edit if open
90	            setIsEditingAssignee(false)
91	            setEditAssignee(card.assignee ?? '')
92	            setSaveError(null)
93	          }}
94	        >
95	          {card.title}
96	        </h3>
97	      )}
98	
99	      {/* Assignee */}
100	      {isEditingAssignee ? (
101	        <div className="card-tile-field-edit">
102	          <input
103	            ref={assigneeInputRef}
104	            aria-label="Edit assignee"
105	            value={editAssignee}
106	            onChange={e => setEditAssignee(e.target.value)}
107	            onKeyDown={e => {
108	              if (e.key === 'Enter')  { skipBlurRef.current = true; handleSaveAssignee() }
109	              if (e.key === 'Escape') { skipBlurRef.current = true; setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }
110	            }}
111	            onBlur={() => {
112	              if (skipBlurRef.current) { skipBlurRef.current = false; return }
113	              handleSaveAssignee()
114	            }}
115	          />
116	          {isSaving && <span aria-label="Saving">Saving…</span>}
117	        </div>
118	      ) : (
119	        <p
120	          className="card-tile-assignee"
121	          onClick={e => {
122	            e.stopPropagation()
123	            setEditAssignee(card.assignee ?? '')
124	            setIsEditingAssignee(true)
125	            // Mutual exclusivity: close title edit if open
126	            setIsEditingTitle(false)
127	            setEditTitle(card.title)
128	            setSaveError(null)
129	          }}
130	        >
131	          {card.assignee ?? 'Unassigned'}
132	        </p>
133	      )}
134	
135	      {card.description && <p className="card-tile-description">{card.description}</p>}
136	      {saveError && <p role="alert" className="card-tile-error">{saveError}</p>}
137	    </div>
138	  )
139	}
