1	import { useEffect, useState, useRef } from 'react'
2	import { createPortal } from 'react-dom'
3	import './CardModal.css'
4	import CommentList from '../CardModal/CommentList.jsx'
5	import BlockEditor from '../CardModal/BlockEditor.jsx'
6	
7	export default function CardModal({ card, onClose, onUpdate, onDelete, onAddComment = () => Promise.resolve() }) {
8	  // Edit state
9	  const [isEditingTitle, setIsEditingTitle] = useState(false)
10	  const [editTitle, setEditTitle]           = useState(card.title)
11	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
12	  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
13	  const [isEditingDescription, setIsEditingDescription] = useState(false)
14	  const [isSaving, setIsSaving]             = useState(false)
15	  const [saveError, setSaveError]           = useState(null)
16	
17	  // Delete state
18	  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
19	  const [isDeleting, setIsDeleting]               = useState(false)
20	
21	  // Focus refs
22	  const titleInputRef    = useRef(null)
23	  const assigneeInputRef = useRef(null)
24	  const skipBlurRef      = useRef(false)
25	
26	  // Focus effects
27	  useEffect(() => {
28	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
29	  }, [isEditingTitle])
30	
31	  useEffect(() => {
32	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
33	  }, [isEditingAssignee])
34	
35	  // Escape key handler — replaces the original handler
36	  useEffect(() => {
37	    function onKey(e) {
38	      if (e.key !== 'Escape') return
39	      if (isEditingTitle) {
40	        skipBlurRef.current = true   // prevent blur from triggering save
41	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
42	      } else if (isEditingAssignee) {
43	        skipBlurRef.current = true   // prevent blur from triggering save
44	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
45	      } else if (isEditingDescription) {
46	        // BlockEditor owns its own Escape handler; CardModal just prevents modal close
47	      } else {
48	        onClose()
49	      }
50	    }
51	    document.addEventListener('keydown', onKey)
52	    return () => document.removeEventListener('keydown', onKey)
53	  }, [onClose, isEditingTitle, isEditingAssignee, isEditingDescription, card.title, card.assignee])
54	
55	  // Save handlers
56	  async function handleSaveTitle() {
57	    if (editTitle.trim() === '') {
58	      setSaveError('Title is required')
59	      return
60	    }
61	    setIsSaving(true); setSaveError(null)
62	    try {
63	      await onUpdate(card.id, { title: editTitle })
64	      setIsEditingTitle(false)
65	    } catch (err) {
66	      setSaveError(err.message)
67	    } finally {
68	      setIsSaving(false)
69	    }
70	  }
71	
72	  async function handleSaveAssignee() {
73	    setIsSaving(true); setSaveError(null)
74	    try {
75	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
76	      setIsEditingAssignee(false)
77	    } catch (err) {
78	      setSaveError(err.message)
79	    } finally {
80	      setIsSaving(false)
81	    }
82	  }
83	
84	  async function handleConfirmDelete() {
85	    setIsDeleting(true); setSaveError(null)
86	    try {
87	      await onDelete(card.id)
88	      onClose()
89	    } catch (err) {
90	      setSaveError(err.message)
91	      setShowDeleteConfirm(false)
92	    } finally {
93	      setIsDeleting(false)
94	    }
95	  }
96	
97	  return createPortal(
98	    <div className="modal-overlay" onClick={onClose}>
99	      <div
100	        className="modal-content"
101	        role="dialog"
102	        aria-modal="true"
103	        aria-label={card.title}
104	        onClick={e => e.stopPropagation()}
105	      >
106	        {/* 1. Close button */}
107	        <button className="modal-close" onClick={onClose} aria-label="Close">
108	          ✕
109	        </button>
110	
111	        {/* 2. Title field (editable) */}
112	        {isEditingTitle ? (
113	          <div className="modal-field-edit">
114	            <input
115	              ref={titleInputRef}
116	              aria-label="Title"
117	              value={editTitle}
118	              onChange={e => setEditTitle(e.target.value)}
119	              onKeyDown={e => { if (e.key === 'Enter') { skipBlurRef.current = true; handleSaveTitle() } }}
120	              onBlur={() => {
121	                if (skipBlurRef.current) { skipBlurRef.current = false; return }
122	                handleSaveTitle()
123	              }}
124	            />
125	            <button aria-label="Save" onMouseDown={() => { skipBlurRef.current = true }} onClick={handleSaveTitle} disabled={isSaving}>
126	              {isSaving ? 'Saving…' : 'Save'}
127	            </button>
128	            <button
129	              aria-label="Cancel"
130	              disabled={isSaving}
131	              onMouseDown={() => { skipBlurRef.current = true }}
132	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
133	            >
134	              Cancel
135	            </button>
136	          </div>
137	        ) : (
138	          <div className="modal-field-view">
139	            <h2 className="modal-title">{card.title}</h2>
140	            <button
141	              aria-label="Edit title"
142	              onClick={() => {
143	                setIsEditingTitle(true); setEditTitle(card.title)
144	                // Mutual exclusivity: close assignee edit if open
145	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
146	              }}
147	            >
148	              Edit
149	            </button>
150	          </div>
151	        )}
152	
153	        {/* 3. Assignee field (editable) */}
154	        {isEditingAssignee ? (
155	          <div className="modal-field-edit">
156	            <input
157	              ref={assigneeInputRef}
158	              aria-label="Assignee"
159	              value={editAssignee}
160	              onChange={e => setEditAssignee(e.target.value)}
161	              onKeyDown={e => { if (e.key === 'Enter') { skipBlurRef.current = true; handleSaveAssignee() } }}
162	              onBlur={() => {
163	                if (skipBlurRef.current) { skipBlurRef.current = false; return }
164	                handleSaveAssignee()
165	              }}
166	            />
167	            <button aria-label="Save" onMouseDown={() => { skipBlurRef.current = true }} onClick={handleSaveAssignee} disabled={isSaving}>
168	              {isSaving ? 'Saving…' : 'Save'}
169	            </button>
170	            <button
171	              aria-label="Cancel"
172	              disabled={isSaving}
173	              onMouseDown={() => { skipBlurRef.current = true }}
174	              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
175	            >
176	              Cancel
177	            </button>
178	          </div>
179	        ) : (
180	          <div className="modal-field-view">
181	            <p className="modal-assignee">
182	              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
183	            </p>
184	            <button
185	              aria-label="Edit assignee"
186	              onClick={() => {
187	                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
188	                // Mutual exclusivity: close title edit if open
189	                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
190	              }}
191	            >
192	              Edit
193	            </button>
194	          </div>
195	        )}
196	
197	        {/* 4. Description (BlockNote editor) */}
198	        <BlockEditor
199	          content={card.description}
200	          onSave={(json) => onUpdate(card.id, { description: json })}
201	          onEditingChange={setIsEditingDescription}
202	        />
203	
204	        {/* 5. Error alert */}
205	        {saveError && <p role="alert" className="modal-error">{saveError}</p>}
206	
207	        {/* 6. Comments section */}
208	        <CommentList
209	          comments={card.comments}
210	          onAddComment={(data) => onAddComment(card.id, data)}
211	        />
212	
213	        {/* 7. Delete button / confirmation */}
214	        {showDeleteConfirm ? (
215	          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
216	            <p>Are you sure you want to delete this card?</p>
217	            <button
218	              aria-label="Confirm delete"
219	              onClick={handleConfirmDelete}
220	              disabled={isDeleting}
221	            >
222	              {isDeleting ? 'Deleting…' : 'Confirm delete'}
223	            </button>
224	            <button
225	              aria-label="Keep card"
226	              onClick={() => setShowDeleteConfirm(false)}
227	              disabled={isDeleting}
228	            >
229	              Keep card
230	            </button>
231	          </div>
232	        ) : (
233	          <button
234	            className="modal-delete"
235	            aria-label="Delete"
236	            onClick={() => setShowDeleteConfirm(true)}
237	          >
238	            Delete
239	          </button>
240	        )}
241	      </div>
242	    </div>,
243	    document.body
244	  )
245	}
