8	export default function Board() {
9	  const { cards, loading, error, createCard, updateCard, deleteCard, addComment } = useBoard()
10	  const [selectedCardId, setSelectedCardId] = useState(null)
11	  const allCards = [...cards.ready, ...cards.in_progress, ...cards.done]
12	  const selectedCard = selectedCardId ? (allCards.find(c => c.id === selectedCardId) ?? null) : null
13	
14	  if (loading) return <div className="board-loading" aria-label="Loading">Loading…</div>
15	  if (error) return <div className="board-error" role="alert">{error}</div>
16	
17	  return (
18	    <div className="board">
19	      <Column
20	        title="Ready"
21	        cards={cards.ready}
22	        onCardClick={(card) => setSelectedCardId(card.id)}
23	        onUpdate={updateCard}
24	        footer={<CreateCardForm onSubmit={createCard} />}
25	      />
26	      <Column title="In Progress" cards={cards.in_progress} onCardClick={(card) => setSelectedCardId(card.id)} onUpdate={updateCard} />
27	      <Column title="Done" cards={cards.done} onCardClick={(card) => setSelectedCardId(card.id)} onUpdate={updateCard} />
28	      {selectedCard && (
29	        <CardModal
30	          card={selectedCard}
31	          onClose={() => setSelectedCardId(null)}
32	          onUpdate={updateCard}
33	          onDelete={deleteCard}
34	          onAddComment={addComment}
35	        />
36	      )}
37	    </div>
38	  )
39	}
