file.content:
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  animation: modal-fade-in 150ms ease;
}

@keyframes modal-fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

.modal-content {
  background: #fff;
  border-radius: 8px;
  padding: 1.5rem;
  max-width: 480px;
  width: 90%;
  position: relative;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
  animation: modal-slide-in 150ms ease;
  max-height: 90vh;
  overflow-y: auto;
}

@keyframes modal-slide-in {
  from { transform: translateY(12px); }
  to   { transform: translateY(0); }
}

.modal-close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  background: none;
  border: none;
  cursor: pointer;
  font-size: 1.1rem;
  color: #666;
}

.modal-close:hover {
  color: #1a1a2e;
}

.modal-title {
  font-size: 1.2rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
  color: #1a1a2e;
}

.modal-assignee {
  font-size: 0.875rem;
  color: #555;
  margin-bottom: 0.5rem;
}

/* Editable fields */
.modal-field-view {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
}

.modal-field-edit {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin-bottom: 0.5rem;
}

.modal-field-edit input {
  flex: 1;
  padding: 0.25rem 0.5rem;
  font-size: 0.875rem;
  border: 1px solid #ccc;
  border-radius: 4px;
}

/* Error alert */
.modal-error {
  color: #c0392b;
  font-size: 0.8rem;
  margin: 0.25rem 0;
}

/* Delete */
.modal-delete {
  margin-top: 1rem;
  background: none;
  border: 1px solid #c0392b;
  color: #c0392b;
  padding: 0.3rem 0.75rem;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.8rem;
}

.modal-delete:hover {
  background: #c0392b;
  color: #fff;
}

.modal-delete-confirm {
  margin-top: 1rem;
  padding: 0.75rem;
  background: #fff5f5;
  border-radius: 6px;
  border: 1px solid #f5c6cb;
}

/* Mobile bottom sheet */
@media (max-width: 600px) {
  .modal-content {
    max-width: 100%;
    width: 100%;
    min-height: 60vh;
    border-radius: 12px 12px 0 0;
    position: fixed;
    bottom: 0;
    padding: 1.25rem;
  }
}

{
  "name": "kanban-app",
  "version": "1.0.0",
  "private": true,
  "workspaces": ["client", "server"],
  "scripts": {
    "dev": "concurrently -n server,client -c blue,green \"npm -w server run dev\" \"npm -w client run dev\"",
    "build": "npm -w client run build",
    "start": "npm -w server run start",
    "test:setup": "node --test test/*.test.mjs",
    "test:server": "npm -w server run test"
  },
  "devDependencies": {
    "concurrently": "^8.2.2"
  }
}

{
  "name": "kanban-server",
  "version": "1.0.0",
  "type": "module",
  "main": "index.js",
  "scripts": {
    "dev": "nodemon index.js",
    "start": "node index.js",
    "test": "node --test test/server.test.mjs test/db.test.mjs test/comments.test.mjs test/ws.test.mjs test/cards.test.mjs"
  },
  "nodemonConfig": {
    "watch": ["./"],
    "ext": "js,json",
    "ignore": ["test/**", "node_modules/**"]
  },
  "dependencies": {
    "express": "^4.18.2",
    "cors": "^2.8.5",
    "better-sqlite3": "^9.4.3",
    "ws": "^8.16.0",
    "uuid": "^9.0.0"
  },
  "devDependencies": {
    "nodemon": "^3.1.0"
  }
}

